content.query:
let _df = '{DeviceFilter}';
let _ip = '{IPFilter}';
let _mac = '{MACFilter}';
let _Net = DeviceNetworkInfo | where Timestamp {TimeRange} | summarize arg_max(Timestamp, IPAddresses, MacAddress) by DeviceId | mv-expand IPE = parse_json(IPAddresses) | extend IP = tostring(IPE.IPAddress) | where isnotempty(IP) and IP !has ':' and IP !startswith '127.' and IP !startswith '169.254.' | summarize LastIPAddress=take_any(IP), IPList=make_set(IP), Mac=take_any(MacAddress) by DeviceId;
DeviceInfo
| where Timestamp {TimeRange}
| summarize arg_max(Timestamp, DeviceType, OSPlatform, OSVersion, OnboardingStatus, SensorHealthState, JoinType, IsAzureADJoined, PublicIP, MachineGroup, ExposureLevel, Vendor, Model) by DeviceId, DeviceName
| join kind=leftouter _Net on DeviceId
| where _df == '' or DeviceName has _df
| where _ip == '' or tostring(IPList) has _ip
| where _mac == '' or Mac has _mac
| extend Category = case(DeviceType in~ ('Workstation','Desktop','Laptop','Server'), 'Computer / Server', DeviceType =~ 'NetworkDevice', 'Network Device', DeviceType =~ 'Printer', 'Printer', DeviceType in~ ('Camera','Webcam','AudioVideoEquipment','VideoSurveillance','AudioAndVideo'), 'Audio & Video', DeviceType in~ ('MobilePhone','Smartphone','Tablet','Mobile'), 'Mobile / Tablet', DeviceType in~ ('IoTDevice','SmartAppliance','CommunicationsDevice','VoIPPhone','GameConsole','MediaPlayer'), 'IoT / Smart Device', OSPlatform has_any ('Windows10','Windows11','WindowsServer','macOS','Linux'), 'Computer / Server', 'Other Network Device')
| extend DomainJoined = case(JoinType =~ 'AAD Joined' or IsAzureADJoined == 1, 'AAD Joined', isnotempty(JoinType), JoinType, 'Not Joined')
| project DeviceName, DeviceId, Category, DeviceType, OSPlatform, OSVersion, OnboardingStatus, SensorHealthState, DomainJoined, LastIPAddress, MAC=Mac, PublicIP, MachineGroup, ExposureLevel, LastSeen=Timestamp
| order by LastSeen desc, DeviceName asc
| top 1000 by LastSeen desc

// Onboarded Computers & Servers Reporting Per Day - first day of window trimmed (telemetry edge)
let _df = '{DeviceFilter}';
let _scope = DeviceInfo
| where Timestamp {TimeRange}
| where DeviceType in~ ('Workstation','Desktop','Laptop','Server') or (OSPlatform has_any ('Windows','Linux','macOS') and DeviceType !in~ ('NetworkDevice','Printer','Camera','Webcam','AudioVideoEquipment','VideoSurveillance','AudioAndVideo','IoTDevice','SmartAppliance','CommunicationsDevice','VoIPPhone','GameConsole','MediaPlayer','MobilePhone','Smartphone','Tablet','Mobile'))
| where _df == '' or DeviceName has _df;
let _firstDay = toscalar(_scope | summarize startofday(min(Timestamp)));
_scope
| extend Kind = case(OSPlatform has 'WindowsServer' or OSPlatform has 'Server' or DeviceType =~ 'Server', 'Windows Server', OSPlatform has_any ('Windows10','Windows11') or DeviceType in~ ('Workstation','Desktop','Laptop'), 'Windows Client', OSPlatform =~ 'macOS', 'macOS', OSPlatform =~ 'Linux', 'Linux', 'Other')
| summarize arg_max(Timestamp, OnboardingStatus) by DeviceId, Day = startofday(Timestamp), Kind
| where OnboardingStatus =~ 'Onboarded'
| where Day > _firstDay
| summarize OnboardedReporting = dcount(DeviceId) by Day, Kind
| order by Kind asc, Day asc
